import api from './app/client';
import type { ExtraShiftDTO, CreateExtraShiftDTO } from '@/types/dto';
import type { Pagination, PaginationParams } from '@/types/api';

export const extraShiftService = {
  getAll: async (params?: Partial<PaginationParams>): Promise<Pagination<ExtraShiftDTO>> => {
    const response = await api.get<Pagination<ExtraShiftDTO>>('/extra-shifts', { params });
    return response.data;
  },

  getByUser: async (userId: string, params?: Partial<PaginationParams>): Promise<Pagination<ExtraShiftDTO>> => {
    const response = await api.get<Pagination<ExtraShiftDTO>>(`/extra-shifts/user/${userId}`, { params });
    return response.data;
  },

  getByRange: async (start: string, end: string): Promise<ExtraShiftDTO[]> => {
    const response = await api.get<ExtraShiftDTO[]>('/extra-shifts/range', {
      params: { start, end }
    });
    return response.data;
  },

  getById: async (id: string): Promise<ExtraShiftDTO> => {
    const response = await api.get<ExtraShiftDTO>(`/extra-shifts/${id}`);
    return response.data;
  },

  create: async (dto: CreateExtraShiftDTO): Promise<ExtraShiftDTO> => {
    const response = await api.post<ExtraShiftDTO>('/extra-shifts', dto);
    return response.data;
  },

  delete: async (id: string): Promise<void> => {
    await api.delete(`/extra-shifts/${id}`);
  }
};
