import React from "react";
import { format } from "date-fns";
import { CheckCircle, XCircle, Unlock } from "lucide-react";
import type { WorkScheduleResponse, TeamMember } from "../types";
import { SCHEDULE_STATUS } from "../constants";
import { getInitials } from "../utils";
import { WorkScheduleStatus } from "@/types/enums";
import { PermissionGate } from "@/components/shared/PermissionGate";
import { PERMISSIONS } from "@/constants/permissions";

interface ScheduleCardProps {
  schedule: WorkScheduleResponse;
  member?: TeamMember;
  approveMutation: any;
  setRejectTargetId: (id: string) => void;
  setRejectTargetName: (name: string) => void;
  setRejectNotes: (notes: string) => void;
  setIsRejectModalOpen: (open: boolean) => void;
  setUnfreezeTargetId: (id: string) => void;
  setIsUnfreezeModalOpen: (open: boolean) => void;
  onViewClick: (schedule: WorkScheduleResponse) => void;
  isCompact?: boolean;
}

export const ScheduleCard: React.FC<ScheduleCardProps> = ({
  schedule,
  member,
  approveMutation,
  setRejectTargetId,
  setRejectTargetName,
  setRejectNotes,
  setIsRejectModalOpen,
  setUnfreezeTargetId,
  setIsUnfreezeModalOpen,
  onViewClick,
}) => {
  const name = member?.name || schedule.userFullName || schedule.userProfile?.fullName || "Unknown";
  const initials = getInitials(name);
  const statusInfo = SCHEDULE_STATUS[schedule.status as WorkScheduleStatus] ?? SCHEDULE_STATUS[WorkScheduleStatus.Draft];
  const StatusIcon = statusInfo.icon;

  const workDayCount = schedule.days.filter((d) => d.dayType === "WorkDay").length;
  const shiftCount = schedule.days.filter((d) => d.shiftType).length;

  const statusChipClass =
    schedule.status === WorkScheduleStatus.Approved
      ? "bg-emerald-50 text-emerald-700 border-emerald-100 dark:bg-emerald-950/60 dark:text-emerald-300 dark:border-emerald-800"
      : schedule.status === WorkScheduleStatus.Submitted
      ? "bg-amber-50 text-amber-700 border-amber-100 dark:bg-amber-950/60 dark:text-amber-300 dark:border-amber-800"
      : schedule.status === WorkScheduleStatus.Rejected
      ? "bg-rose-50 text-rose-700 border-rose-100 dark:bg-rose-950/60 dark:text-rose-300 dark:border-rose-800"
      : "bg-muted/50 text-muted-foreground border-border";

  return (
    <tr className="hover:bg-muted/30 transition-all group border-b border-border">
      {/* 1. Team Member */}
      <td className="px-6 py-5">
        <div className="flex items-center gap-4">
          <div
            className="w-11 h-11 rounded-2xl flex items-center justify-center text-[11px] font-black shrink-0 shadow-sm transition-transform group-hover:scale-105 border"
            style={{
              backgroundColor: `${member?.hexColor}15`,
              borderColor: `${member?.hexColor}40`,
              color: member?.hexColor
            }}
          >
            {initials}
          </div>
          <div className="flex flex-col min-w-0">
            <p className="text-sm font-bold tracking-tight truncate" style={{ color: member?.hexColor }}>{name}</p>
            <p className="text-[10px] text-muted-foreground font-medium uppercase tracking-widest mt-0.5 truncate">{member?.email || "Operational Staff"}</p>
          </div>
        </div>
      </td>

      {/* 2. Period */}
      <td className="px-6 py-5">
        <div className="inline-flex items-center gap-2 px-3 py-1 bg-muted/50 border border-border rounded-lg">
          <p className="text-xs font-bold text-muted-foreground">
            {format(new Date(schedule.year, schedule.month - 1, 1), "MMMM yyyy")}
          </p>
        </div>
      </td>

      {/* 3. Shifts / Days */}
      <td className="px-6 py-5">
        <div className="flex items-center justify-center gap-6">
          <div className="flex flex-col items-center">
            <span className="text-[9px] font-bold text-muted-foreground uppercase tracking-widest mb-1">Shifts</span>
            <span className="text-sm font-black text-primary leading-none">{shiftCount}</span>
          </div>
          <div className="w-px h-6 bg-border" />
          <div className="flex flex-col items-center">
            <span className="text-[9px] font-bold text-muted-foreground uppercase tracking-widest mb-1">Work</span>
            <span className="text-sm font-black text-emerald-600 dark:text-emerald-400 leading-none">{workDayCount}</span>
          </div>
        </div>
      </td>

      {/* 4. Status & Notes */}
      <td className="px-6 py-5">
        <div className="flex flex-col gap-2.5">
          <div className={`inline-flex items-center gap-2 px-3 py-1 rounded-full border text-[10px] font-bold uppercase tracking-widest w-fit ${statusChipClass}`}>
            <StatusIcon className="w-3 h-3" />
            {statusInfo.label}
          </div>

          {schedule.status === WorkScheduleStatus.Rejected && schedule.reviewNotes && (
            <div className="p-3 bg-rose-50/40 dark:bg-rose-950/20 border border-rose-100 dark:border-rose-900 rounded-xl max-w-[240px] whitespace-normal">
              <p className="text-[9px] font-bold text-rose-600 dark:text-rose-400 uppercase tracking-widest mb-1">Admin Feedback</p>
              <p className="text-[11px] text-rose-700 dark:text-rose-300 font-medium leading-relaxed italic line-clamp-2">
                "{schedule.reviewNotes}"
              </p>
            </div>
          )}
        </div>
      </td>

      {/* 5. Actions */}
      <td className="px-6 py-5">
        <div className="flex items-center justify-end gap-2">
          <button
            onClick={() => onViewClick(schedule)}
            className="px-3 py-1.5 text-xs font-bold text-muted-foreground hover:text-foreground hover:bg-muted rounded-lg transition-all"
          >
            View Details
          </button>

          {schedule.status === WorkScheduleStatus.Submitted && (
            <PermissionGate permission={PERMISSIONS.WorkSchedule.Approve} mode="disable">
              <div className="flex items-center gap-1.5 ml-2">
                <button
                  onClick={() => approveMutation.mutate(schedule.id)}
                  className="flex items-center gap-1.5 px-4 py-1.5 bg-emerald-600 text-white text-[11px] font-bold rounded-lg shadow-lg shadow-emerald-500/20 hover:bg-emerald-700 active:scale-95 transition-all"
                >
                  <CheckCircle size={14} />
                  Approve
                </button>
                <button
                  onClick={() => {
                    setRejectTargetId(schedule.id);
                    setRejectTargetName(name);
                    setRejectNotes("");
                    setIsRejectModalOpen(true);
                  }}
                  className="flex items-center gap-1.5 px-4 py-1.5 bg-card border border-rose-200 dark:border-rose-800 text-rose-600 dark:text-rose-400 text-[11px] font-bold rounded-lg hover:bg-rose-50 dark:hover:bg-rose-950/20 transition-all"
                >
                  <XCircle size={14} />
                  Reject
                </button>
              </div>
            </PermissionGate>
          )}

          {schedule.status === WorkScheduleStatus.Approved && (
            <PermissionGate permission={PERMISSIONS.WorkSchedule.Update} mode="disable">
              <button
                onClick={() => { setUnfreezeTargetId(schedule.id); setIsUnfreezeModalOpen(true); }}
                className="flex items-center gap-2 px-4 py-1.5 bg-foreground text-background text-[11px] font-bold rounded-lg shadow-sm hover:bg-foreground/90 transition-all"
              >
                <Unlock size={14} />
                Unfreeze
              </button>
            </PermissionGate>
          )}

          {(schedule.status === WorkScheduleStatus.Draft || schedule.status === WorkScheduleStatus.Rejected) && (
            <div
              className={`px-4 py-1.5 rounded-lg border text-[10px] font-bold uppercase tracking-widest shadow-sm ${
                schedule.status === WorkScheduleStatus.Draft
                  ? "bg-primary/10 text-primary border-primary/20"
                  : "bg-amber-50 text-amber-700 border-amber-100 dark:bg-amber-950/60 dark:text-amber-300 dark:border-amber-800"
              }`}
            >
              {schedule.status === WorkScheduleStatus.Draft ? "Awaiting Submission" : "Pending Revision"}
            </div>
          )}
        </div>
      </td>
    </tr>
  );
};
